def smith_waterman(seq1, seq2, match_score=2, mismatch_score=-1, gap_score=-1):
    m, n = len(seq1), len(seq2)
    score_matrix = [[0] * (n + 1) for _ in range(m + 1)]
    max_score = 0

    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if seq1[i - 1] == seq2[j - 1]:
                score_matrix[i][j] = score_matrix[i - 1][j - 1] + match_score
            else:
                score_matrix[i][j] = max(0, score_matrix[i - 1][j - 1] + mismatch_score, score_matrix[i][j - 1] + gap_score, score_matrix[i - 1][j] + gap_score)
            max_score = max(max_score, score_matrix[i][j])

    return max_score

